function countExcellentPairs(nums, k) {
    let frequency = new Map();
    for (let num of nums) {
        frequency.set(num, (frequency.get(num) || 0) + 1);
    }

    let count = 0;
    for (let [num1, freq1] of frequency.entries()) {
        for (let [num2, freq2] of frequency.entries()) {
            let setBits = (num1 | num2).toString(2).replace(/0/g, '').length + (num1 & num2).toString(2).replace(/0/g, '').length;
            if (setBits >= k) {
                count += (num1 === num2) ? freq1 * (freq1 - 1) / 2 : freq1 * freq2;
            }
        }
    }

    return count;
}
```

    The algorithm first counts the frequency of each number in the input array using a hash map. Next, it iterates over all pairs of distinct numbers in the map (including pairs of identical numbers). For each pair, it calculates the number of set bits in both the bitwise OR and bitwise AND of the two numbers. If the sum of set bits is greater than or equal to the target value k, the algorithm increments the count of excellent pairs accordingly. If the pair consists of identical numbers, the count is incremented by the triangular number of the count of that number in the input array, otherwise the count is incremented by the product of the counts of the two numbers.

The time complexity of this algorithm is O(n^2), where n is the number of distinct numbers in the input array. The space complexity is also O(n), as a hash map is used to store the frequency of each number.

